
export default function Page() {
    // 從後端獲取數據的示例
    const products = [{
        product_id: 1,
        product_key: 'A001',
        product_name: '示例商品 A',
        category: '電子',
        price: 199,
        stock_quantity: 10,
        image_url: 'https://via.placeholder.com/240x240?text=A',
    },
    {
        product_id: 2,
        product_key: 'B001',
        product_name: '示例商品 B',
        category: '生活',
        price: 299,
        stock_quantity: 5,
        image_url: 'https://via.placeholder.com/240x240?text=B',
    },]

    return (
        <div className="page-container">
            <div className="product-grid product-list-container">
                {products.map((product) => (
                    <div className="product-card">
                        <img
                            src={product.image_url}
                            alt={product.product_name}
                            className="product-image"
                        />
                        <div className="product-info">
                            <h3>{product.product_name}</h3>
                            <p>{product.category}</p>
                            <p>價格：${product.price}</p>
                            <p>庫存：{product.stock_quantity}</p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}